"use strict";(self.webpackChunkcentrifugal_dev=self.webpackChunkcentrifugal_dev||[]).push([[980],{15042:e=>{e.exports=JSON.parse('{"permalink":"/blog/2026/05/24/pg-stream-broker-benefits","editUrl":"https://github.com/centrifugal/centrifugal.dev/edit/main/blog/2026-05-24-pg-stream-broker-benefits.md","source":"@site/blog/2026-05-24-pg-stream-broker-benefits.md","title":"Transactional publishing for stream subscriptions with PostgreSQL","description":"The PostgreSQL stream broker brings transactional publishing to Centrifugo\'s stream subscriptions. Real-time updates commit alongside the database write that triggers them \u2014 same SQL transaction, no application-side outbox, no CDC pipeline, no separate publish API call.","date":"2026-05-24T00:00:00.000Z","tags":[{"inline":true,"label":"centrifugo","permalink":"/blog/tags/centrifugo"},{"inline":true,"label":"postgresql","permalink":"/blog/tags/postgresql"},{"inline":true,"label":"streams","permalink":"/blog/tags/streams"},{"inline":true,"label":"outbox","permalink":"/blog/tags/outbox"}],"readingTime":10.07,"hasTruncateMarker":true,"authors":[{"name":"Alexander Emelin","title":"Founder of Centrifugal Labs","imageURL":"/img/alexander_emelin.jpeg","key":null,"page":null}],"frontMatter":{"title":"Transactional publishing for stream subscriptions with PostgreSQL","tags":["centrifugo","postgresql","streams","outbox"],"description":"The PostgreSQL stream broker brings transactional publishing to Centrifugo\'s stream subscriptions. Real-time updates commit alongside the database write that triggers them \u2014 same SQL transaction, no application-side outbox, no CDC pipeline, no separate publish API call.","author":"Alexander Emelin","authorTitle":"Founder of Centrifugal Labs","authorImageURL":"/img/alexander_emelin.jpeg","image":"/img/blog_pg_stream_broker.jpg","hide_table_of_contents":false,"draft":false},"unlisted":false,"prevItem":{"title":"Multi-node Centrifugo on PostgreSQL alone","permalink":"/blog/2026/05/25/pg-controller-multi-node"},"nextItem":{"title":"Map subscriptions (Part 2) \u2014 when your PostgreSQL transaction is your real-time publish","permalink":"/blog/2026/05/23/map-subscriptions-part-2"}}')},28453:(e,t,a)=>{a.d(t,{R:()=>i,x:()=>o});var n=a(96540);const s={},r=n.createContext(s);function i(e){const t=n.useContext(r);return n.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),n.createElement(r.Provider,{value:t},e.children)}},36867:(e,t,a)=>{a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>h,frontMatter:()=>i,metadata:()=>n,toc:()=>c});var n=a(15042),s=a(74848),r=a(28453);const i={title:"Transactional publishing for stream subscriptions with PostgreSQL",tags:["centrifugo","postgresql","streams","outbox"],description:"The PostgreSQL stream broker brings transactional publishing to Centrifugo's stream subscriptions. Real-time updates commit alongside the database write that triggers them \u2014 same SQL transaction, no application-side outbox, no CDC pipeline, no separate publish API call.",author:"Alexander Emelin",authorTitle:"Founder of Centrifugal Labs",authorImageURL:"/img/alexander_emelin.jpeg",image:"/img/blog_pg_stream_broker.jpg",hide_table_of_contents:!1,draft:!1},o=void 0,l={authorsImageUrls:[void 0]},c=[{value:"The dual-write problem, revisited",id:"the-dual-write-problem-revisited",level:2},{value:"Publishing inside your transaction",id:"publishing-inside-your-transaction",level:2},{value:"App-owned state with stream subscriptions",id:"app-owned-state-with-stream-subscriptions",level:2},{value:"A concrete example: Kafka aggregator + live snapshot",id:"a-concrete-example-kafka-aggregator--live-snapshot",level:2},{value:"A second shape: per-tenant channels",id:"a-second-shape-per-tenant-channels",level:2},{value:"Performance",id:"performance",level:2},{value:"Getting started",id:"getting-started",level:2}];function d(e){const t={a:"a",admonition:"admonition",code:"code",em:"em",h2:"h2",li:"li",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,r.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(t.p,{children:["In ",(0,s.jsx)(t.a,{href:"/blog/2026/05/23/map-subscriptions-part-2",children:"Part 2 of the map subscriptions series"}),", we introduced a PostgreSQL map broker that lets your application publish real-time map updates inside a database transaction \u2014 removing the dual-write problem when you publish via the broker's SQL function from your own transactions. That capability applied only to map subscriptions \u2014 keyed state like leaderboards, collaborative boards, and inventories."]}),"\n",(0,s.jsxs)(t.p,{children:["Today we're extending the same shape to ",(0,s.jsx)(t.strong,{children:"stream subscriptions"})," \u2014 the ordered-event primitive that powers notifications, activity feeds, chat messages, audit logs, and order updates. If you have a database row and you want to announce a change in real time, you can now do it atomically with your write \u2014 same ",(0,s.jsx)(t.code,{children:"BEGIN / COMMIT"}),', same outbox architecture, same "no Redis" simplicity.']}),"\n",(0,s.jsx)(t.admonition,{title:"New and evolving",type:"info",children:(0,s.jsx)(t.p,{children:"Available in Centrifugo v6.8.0+. The PostgreSQL stream broker is a recent addition \u2014 we're eager for feedback. SQL function shapes, configuration keys, and outbox internals may still adjust before they're considered stable."})}),"\n",(0,s.jsx)(t.admonition,{title:"TL;DR",type:"tip",children:(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:["Call ",(0,s.jsx)(t.code,{children:"cf_stream_publish(...)"})," inside the same SQL transaction as your row write \u2014 both commit atomically. No outbox table to manage in your app, no CDC pipeline, no dual-write gap."]}),"\n",(0,s.jsxs)(t.li,{children:["The broker shares its outbox infrastructure with the ",(0,s.jsx)(t.a,{href:"/blog/2026/05/23/map-subscriptions-part-2",children:"PG map broker"})," \u2014 partitioned table, ",(0,s.jsx)(t.code,{children:"LISTEN/NOTIFY"})," for low-latency wakeup, vacuum-free retention."]}),"\n",(0,s.jsxs)(t.li,{children:["Pairs with a ",(0,s.jsx)(t.code,{children:"getState"})," callback in the SDK: load app-owned state plus a stream position in one shot; the SDK subscribes from there and recovers automatically on reconnect."]}),"\n",(0,s.jsxs)(t.li,{children:["Two concrete shapes worked through below: an aggregator-as-publisher fronting a Kafka feed, and per-tenant channels (one per restaurant) over a shared ",(0,s.jsx)(t.code,{children:"orders"})," table."]}),"\n"]})}),"\n",(0,s.jsx)(t.h2,{id:"the-dual-write-problem-revisited",children:"The dual-write problem, revisited"}),"\n",(0,s.jsx)(t.p,{children:"Integrating a real-time system with a relational database creates the same gap: the backend writes to the database, then publishes to the real-time layer as a separate operation. If the process crashes between them \u2014 or if the publish fails \u2014 the database and subscribers fall out of sync. Users see stale data until they refresh."}),"\n",(0,s.jsxs)(t.p,{children:["We ",(0,s.jsx)(t.a,{href:"/blog/2026/05/23/map-subscriptions-part-2#the-dual-write-problem",children:"covered this in depth"})," for map subscriptions. The same problem applies \u2014 even more broadly \u2014 to stream subscriptions. Every notification system, every audit trail, every order-status feed has the same shape: write a row to your database, then announce the change over WebSocket. The PostgreSQL stream broker lets you combine both into one transaction."]}),"\n",(0,s.jsx)(t.h2,{id:"publishing-inside-your-transaction",children:"Publishing inside your transaction"}),"\n",(0,s.jsxs)(t.p,{children:["Centrifugo creates a ",(0,s.jsx)(t.code,{children:"cf_stream_publish"})," SQL function when the PostgreSQL stream broker initializes. Your application calls it inside its own transaction:"]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-sql",children:"BEGIN;\n  -- Business logic: update order status\n  UPDATE orders SET status = 'shipped', updated_at = NOW()\n  WHERE id = 42;\n\n  -- Publish to real-time channel (same transaction)\n  SELECT * FROM cf_stream_publish(\n    p_channel := 'orders:42',\n    p_data    := '{\"status\": \"shipped\"}'::jsonb\n  );\nCOMMIT;\n"})}),"\n",(0,s.jsxs)(t.p,{children:["If the transaction rolls back, the real-time update never happened. No outbox table to manage in your application, no CDC pipeline, no eventual consistency \u2014 just a single transaction. The architecture is the same outbox pattern we use for map subscriptions: all writes land in PostgreSQL tables atomically, and Centrifugo's outbox workers pick up new entries and deliver them to subscribers. When ",(0,s.jsx)(t.code,{children:"use_notify"})," is enabled, delivery latency drops to low single-digit milliseconds."]}),"\n",(0,s.jsxs)(t.p,{children:["The transactional guarantee applies to ",(0,s.jsx)(t.strong,{children:"callers using the SQL function path"})," \u2014 i.e. your backend code calling ",(0,s.jsx)(t.code,{children:"cf_stream_publish"})," directly inside its own SQL transaction alongside the row write. Publishes that go through Centrifugo's HTTP/GRPC API remain a separate operation from your DB write (the historic dual-write shape) \u2014 same as before. The SQL function path is what removes that gap; it's an additional integration option, not a change to existing publish APIs."]}),"\n",(0,s.jsx)(t.h2,{id:"app-owned-state-with-stream-subscriptions",children:"App-owned state with stream subscriptions"}),"\n",(0,s.jsxs)(t.p,{children:["For applications where the data already lives in your own tables \u2014 orders, notifications, activity feeds, chat \u2014 the stream broker is enough on its own. No duplicate state table, no broker-managed snapshot. Your app database is the source of truth; Centrifugo streams only the change events. The stream broker keeps a thin bridging window in ",(0,s.jsx)(t.code,{children:"cf_stream"})," (the partition retention window) while your app DB owns historical data."]}),"\n",(0,s.jsxs)(t.p,{children:["The client SDK now supports a ",(0,s.jsx)(t.code,{children:"getState"})," callback for stream subscriptions that automates this pattern. We ",(0,s.jsx)(t.a,{href:"/blog/2024/06/03/real-time-document-state-sync",children:"previously described"})," the challenge of keeping document state loaded from a REST API in sync with a real-time subscription \u2014 the race window between the HTTP response and the subscription start, the need to handle ",(0,s.jsx)(t.code,{children:"recovered: false"})," on reconnects, the manual position tracking. The ",(0,s.jsx)(t.code,{children:"getState"})," callback solves all of this natively:"]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-javascript",children:"const sub = client.newSubscription('orders:user_42', {\n  getState: async () => {\n    // 1. Capture stream position FIRST\n    const pos = await api.getStreamPosition('orders:user_42');\n    // 2. Then load your data\n    const orders = await api.getOrders(42);\n    renderOrders(orders);\n    // 3. Return the position \u2014 SDK recovers from here\n    return { offset: pos.offset, epoch: pos.epoch };\n  },\n});\n\nsub.on('publication', (ctx) => {\n  // Incremental updates \u2014 applied after getState on initial load,\n  // and after each reconnect where recovery succeeds.\n  applyOrderUpdate(ctx.data);\n});\n\nsub.subscribe();\n"})}),"\n",(0,s.jsxs)(t.p,{children:["The callback is called on initial subscribe and when recovery fails after a reconnect. On normal reconnects where the server successfully recovers missed publications, ",(0,s.jsx)(t.code,{children:"getState"})," is not called \u2014 recovered publications simply arrive as ",(0,s.jsx)(t.code,{children:"publication"})," events. When recovery fails (history expired, epoch changed), the SDK calls ",(0,s.jsx)(t.code,{children:"getState"})," again automatically: the app refreshes from its source of truth, and the SDK resubscribes from the fresh position."]}),"\n",(0,s.jsxs)(t.p,{children:["The position should come from ",(0,s.jsx)(t.code,{children:"cf_stream_top_position"}),", called inside the same transaction (or before) your data read. Reading position first ensures it's a lower bound \u2014 recovered publications may overlap with your loaded data, but you'll never have gaps. This works correctly when updates are idempotent (e.g. \"set status to shipped\"). For non-idempotent updates, deduplicate by publication offset \u2014 the same caveat we described in ",(0,s.jsx)(t.a,{href:"/blog/2024/06/03/real-time-document-state-sync",children:"Proper real-time document state synchronization"}),", but now handled by the SDK rather than application code."]}),"\n",(0,s.jsx)(t.p,{children:"On error (network failure, database timeout), the SDK emits an error event and retries with backoff."}),"\n",(0,s.jsx)(t.h2,{id:"a-concrete-example-kafka-aggregator--live-snapshot",children:"A concrete example: Kafka aggregator + live snapshot"}),"\n",(0,s.jsx)(t.p,{children:"One concrete integration pattern this design handles particularly well: a service that consumes a Kafka topic and maintains aggregated views in PostgreSQL \u2014 say, a price board built from a market-data topic. The browser client needs to fetch the current aggregate and then receive live updates. With Centrifugo as a separate Kafka consumer fanning the same topic out to WebSocket subscribers, you end up bridging two unrelated offset spaces \u2014 the snapshot row stores a Kafka offset, the live subscription speaks Centrifugo offsets, and the client has to subscribe with a recent stream position and discard everything older than the snapshot's Kafka offset. It works, but the bridging logic is awkward and easy to get subtly wrong."}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{children:"\u2500\u2500\u2500 Write path (single PG txn ties snapshot + publish) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n   Kafka topic\n       \u2502 batch\n       \u25bc\n  \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n  \u2502 Aggregator \u2502\n  \u2514\u2500\u2500\u2500\u2500\u2500\u252c\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n        \u2502   BEGIN\n        \u2502     UPDATE snapshot SET aggregate = ...\n        \u2502     cf_stream_publish(p_channel := ch, p_data := evt)\n        \u2502   COMMIT              \u2190 both land atomically\n        \u25bc\n  \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n  \u2502          PostgreSQL          \u2502\n  \u2502   \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510 \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510  \u2502\n  \u2502   \u2502 snapshot \u2502 \u2502cf_stream \u2502  \u2502\n  \u2502   \u2502   row    \u2502 \u2502  outbox  \u2502  \u2502\n  \u2502   \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518 \u2514\u2500\u2500\u2500\u2500\u252c\u2500\u2500\u2500\u2500\u2500\u2518  \u2502\n  \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u252c\u2534\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n                       \u2502 LISTEN/NOTIFY + poll\n                       \u25bc\n                 \u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n                 \u2502  Centrifugo  \u2502\n                 \u2502 (PG broker)  \u2502\n                 \u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518\n\n\n\u2500\u2500\u2500 Read path (position first; catch-up applied idempotently) \u2500\u2500\u2500\u2500\n\n  Browser \u2500\u25001. GET /state\u2500\u2500\u25ba App server\n                                 \u2502 pos  = cf_stream_top_position(ch)\n                                 \u2502 snap = SELECT aggregate FROM ...\n  Browser \u25c4\u2500\u2500\u2500\u2500 (snap, pos) \u2500\u2500\u2500\u2500\u2500\u2518\n\n  Browser \u2500\u25002. subscribe(ch, since=pos)\u2500\u2500\u25ba Centrifugo\n  Browser \u25c4\u2500\u2500\u2500 catch-up from pos \u2192 live \u2500\u2500\u2518\n             (events committed between the two reads\n              arrive here; idempotent apply reconciles)\n"})}),"\n",(0,s.jsxs)(t.p,{children:["The PG stream broker collapses this if you make the aggregator the publisher to Centrifugo (instead of Centrifugo reading Kafka in parallel). For each Kafka batch the aggregator processes, it does \u2014 in one PG transaction \u2014 both the snapshot UPDATE ",(0,s.jsx)(t.em,{children:"and"})," a ",(0,s.jsx)(t.code,{children:"cf_stream_publish(...)"})," for the new event(s). Snapshot mutation and broker publish commit together; they can never disagree about what's been observed. The snapshot row stays minimal \u2014 just the aggregate, no offset bookkeeping."]}),"\n",(0,s.jsxs)(t.p,{children:["The client's ",(0,s.jsx)(t.code,{children:"getState"})," follows the same recipe shown earlier: read ",(0,s.jsx)(t.code,{children:"cf_stream_top_position"})," first, then read the snapshot, return the captured position. Position first makes it a lower bound \u2014 events committed between the two reads arrive as stream catch-up on top of the snapshot, and the application applies them idempotently (the same assumption ",(0,s.jsx)(t.code,{children:"getState"})," requires in general). For a price-board aggregate this is natural: each event is an absolute price, not a delta."]}),"\n",(0,s.jsxs)(t.p,{children:["If you'd rather eliminate that replay window entirely \u2014 for example, when events are non-idempotent deltas and you don't want to add offset-based dedup \u2014 wrap both reads in a single ",(0,s.jsx)(t.code,{children:"REPEATABLE READ"})," transaction. Both reads then see the same MVCC snapshot: the returned position is the exact watermark baked into the snapshot, and catch-up delivers only events committed strictly after it \u2014 no overlap to reconcile at all."]}),"\n",(0,s.jsx)(t.p,{children:"This shape \u2014 aggregator-as-publisher, single-tx atomicity for the snapshot update + the publish \u2014 is the natural fit whenever you have an upstream feed (Kafka, NATS, CDC, anything else) being shaped into stored views. The PG stream broker removes the cross-system offset bridge by making one process responsible for both the stored aggregate and the change stream."}),"\n",(0,s.jsx)(t.h2,{id:"a-second-shape-per-tenant-channels",children:"A second shape: per-tenant channels"}),"\n",(0,s.jsxs)(t.p,{children:["The Kafka example is one flavor \u2014 an upstream feed shaped into a single aggregate. A second, very common flavor is internal writes partitioned by tenant: one shared table, many independent consumers. A kitchen-orders system is a clean example \u2014 a single ",(0,s.jsx)(t.code,{children:"orders"})," table across all restaurants, but each restaurant's kitchen display only cares about its own channel. The demo below is runnable from the ",(0,s.jsx)(t.a,{href:"https://github.com/centrifugal/examples/tree/master/v6/pg_stream_broker",children:"pg_stream_broker example"})," on GitHub:"]}),"\n",(0,s.jsx)("video",{width:"100%",loop:!0,autoPlay:"autoplay",muted:!0,controls:"",src:"/img/demo_kitchen.mp4"}),"\n",(0,s.jsxs)(t.p,{children:["The channel shape is ",(0,s.jsx)(t.code,{children:"kitchen:{restaurant_id}"}),". Every write to a restaurant's orders commits atomically with a publish on that restaurant's channel:"]}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-sql",children:"BEGIN;\n  INSERT INTO orders (id, restaurant_id, status, items, updated_at)\n  VALUES (7001, 42, 'received', $1, NOW());\n\n  SELECT cf_stream_publish(\n    p_channel := 'kitchen:42',\n    p_data    := '{\"order_id\":7001,\"status\":\"received\",...}'::jsonb\n  );\nCOMMIT;\n"})}),"\n",(0,s.jsxs)(t.p,{children:["Status transitions (",(0,s.jsx)(t.code,{children:"received"})," \u2192 ",(0,s.jsx)(t.code,{children:"preparing"})," \u2192 ",(0,s.jsx)(t.code,{children:"ready"})," \u2192 ",(0,s.jsx)(t.code,{children:"served"}),") do the same \u2014 ",(0,s.jsx)(t.code,{children:"UPDATE orders"})," + ",(0,s.jsx)(t.code,{children:"cf_stream_publish(p_channel := 'kitchen:42', \u2026)"})," in one transaction. The application must follow one rule: every code path that mutates a row for restaurant X emits the publish for ",(0,s.jsx)(t.code,{children:"kitchen:X"})," in the same transaction."]}),"\n",(0,s.jsx)(t.p,{children:"The read path is the position-first recipe from earlier, with the snapshot filtered by restaurant:"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-sql",children:"SELECT * FROM cf_stream_top_position('kitchen:42');\n\nSELECT id, status, items, updated_at\nFROM orders\nWHERE restaurant_id = 42\n  AND status IN ('received','preparing','ready');\n"})}),"\n",(0,s.jsxs)(t.p,{children:["Each channel has its own meta row and its own ",(0,s.jsx)(t.code,{children:"top_offset"}),"; writes on ",(0,s.jsx)(t.code,{children:"kitchen:99"})," never block or interfere with ",(0,s.jsx)(t.code,{children:"kitchen:42"}),". This scales naturally to thousands of tenants on a single PostgreSQL \u2014 each channel is an independent append-only stream, and the shared ",(0,s.jsx)(t.code,{children:"cf_stream"})," partitioned table just absorbs the union. For the kitchen scenario, events carry ",(0,s.jsx)(t.code,{children:"order_id"})," plus ",(0,s.jsx)(t.code,{children:"updated_at"}),", so the client applies them as upserts with last-write-wins \u2014 any catch-up replay between the two reads is reconciled automatically."]}),"\n",(0,s.jsx)(t.h2,{id:"performance",children:"Performance"}),"\n",(0,s.jsx)(t.p,{children:"On a local PostgreSQL 16 (Homebrew, Apple M4):"}),"\n",(0,s.jsxs)(t.table,{children:[(0,s.jsx)(t.thead,{children:(0,s.jsxs)(t.tr,{children:[(0,s.jsx)(t.th,{children:"Operation"}),(0,s.jsx)(t.th,{children:"Result"})]})}),(0,s.jsxs)(t.tbody,{children:[(0,s.jsxs)(t.tr,{children:[(0,s.jsx)(t.td,{children:(0,s.jsx)(t.strong,{children:"Publish"})}),(0,s.jsx)(t.td,{children:"~17,000 ops/sec"})]}),(0,s.jsxs)(t.tr,{children:[(0,s.jsx)(t.td,{children:(0,s.jsx)(t.strong,{children:"Publish \u2192 delivery latency"})}),(0,s.jsx)(t.td,{children:"~2 ms"})]}),(0,s.jsxs)(t.tr,{children:[(0,s.jsxs)(t.td,{children:[(0,s.jsx)(t.strong,{children:"Partition drop"})," (10K rows)"]}),(0,s.jsx)(t.td,{children:"~1 ms"})]})]})]}),"\n",(0,s.jsxs)(t.p,{children:["These numbers are from a single Centrifugo instance running the broker's Go integration tests in benchmark mode against the same machine's PostgreSQL \u2014 small JSON payloads, default broker configuration, parallel goroutines exercising ",(0,s.jsx)(t.code,{children:"cf_stream_publish"}),". They're rough estimates, not numbers you can take to production: real workloads vary with payload size, connection pool, network latency, and your PostgreSQL's own write capacity. In production, multiple Centrifugo nodes and application instances call ",(0,s.jsx)(t.code,{children:"cf_stream_publish"})," concurrently \u2014 aggregate throughput scales with the number of writers up to PostgreSQL's own write capacity. For notification, audit-log, and order-update workloads this is plenty of headroom. For ultra-high-volume telemetry that doesn't need transactional publishing, the Redis broker remains the right choice."]}),"\n",(0,s.jsx)(t.h2,{id:"getting-started",children:"Getting started"}),"\n",(0,s.jsx)(t.p,{children:"Configure the PostgreSQL stream broker as your Centrifugo broker:"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-json",metastring:'title="config.json"',children:'{\n  "broker": {\n    "enabled": true,\n    "type": "postgres",\n    "postgres": {\n      "dsn": "postgres://user:pass@localhost:5432/app?sslmode=disable",\n      "use_notify": true,\n      "partition_retention_days": 7\n    }\n  }\n}\n'})}),"\n",(0,s.jsxs)(t.p,{children:["The broker automatically creates the required tables and SQL functions on startup. Call ",(0,s.jsx)(t.code,{children:"cf_stream_publish"})," from your application's SQL transactions to publish atomically."]}),"\n",(0,s.jsxs)(t.p,{children:["Read the full ",(0,s.jsx)(t.a,{href:"/docs/server/engines#postgresql-broker",children:"stream broker documentation"})," for configuration reference, and see the ",(0,s.jsx)(t.a,{href:"/blog/2026/05/23/map-subscriptions-part-2",children:"map subscriptions Part 2"})," post for the outbox architecture deep-dive that both brokers share."]})]})}function h(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}}}]);